#include<bits/stdc++.h>
using namespace std;
const int N = 1e5+5;
struct hod{int s,k;}a[N];
int n,sum[N],p[N],q[N];
bool cmp(hod h1,hod h2){return h1.k>h2.k;}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i].s;
    for(int i=1;i<=n;i++)cin>>a[i].k;
    sort(a+1,a+n+1,cmp);
    for(int i=1;i<=n;i++)sum[i]=sum[i-1]+a[i].k;
    for(int i=1;i<=n;i++)p[i]=max(p[i-1],a[i].s*2);
    for(int i=n;i>=1;i--)q[i]=max(q[i+1],a[i].s*2+a[i].k);
    for(int i=1;i<=n;i++)cout<<max(sum[i]+p[i],sum[i-1]+q[i])<<"\n";
    return 0;
}
